_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
uv1 = (vUv-0.5)*uAspect;
krad = 0.25 ;

float k= sin(q10*M_PI*2-vRadius*8)*q12;
kstrength = q15;

//kstrength = 1;

r1 = length(uv1 * (1+vec2 (cos(q10*6),sin(q10*6))*0.015*q12));
r2 = pow(r1/krad,2);
arg = 0.4*r2/(1.4-r2);
inside = r2<1;
fullk = kstrength>0.99;
kmod_uv = (inside ? (1+ arg):1/r1)*kstrength;

uv1 = uv1*(1+kstrength*(-1+ kmod_uv))*1.2;
uv10 = uv1;
float a = M_PI*inside*fullk*(q20*(sin(q2*4)>0)*2);
uv1 = multiply(uv1,mat2(sin(a), cos(a),-cos(a),sin(a)));

uv1.x+=q20*(r2<1)*fullk;;
uv1.y+=q21*(r2<1)*fullk;

uv1 += 0.5;
ret0 = 0;
for (int n = 0; n <= anz; n++)
{
  float ang1, ca, sa;
  ang1 = 3.14*n/anz*.05*q26;; //Im Kug mode mehr rotieren !
  sincos(ang1,sa,ca);
  float mm = .5;
  uv1 = multiply(uv1-mm,mat2(ca,sa,-sa,ca))+mm;
  uv1 = vec2((uv1.x), (abs(uv1.y-size)+size));
  uv1 = min(uv1,(1-uv1));
  uv1 = 0.5 + (1.0 - abs( fract(uv1 * .5) * 2 - 1.0 )-.5);
//  uv3= uv1+0.002*k*(1-kstrength)+ (kstrength>=0.9)*(r2>1)*(r1*2.0*exp(-q12)-q10*kstrength*0.5) ;
  uv3= uv1+0.002*k +vRadius*exp(-q12)*kstrength*!inside;
  uv3 = 0.5 + (1.0 - abs( fract(uv3 * .5) * 2 - 1.0 )-.5);
  ret0 += GetBlur1(uv3)/anz;
}


ret = mix(GetPixel(uv3), ret0,0.6);
ret = mix(ret, GetBlur1(uv3), kstrength*r2*r2*inside);
ret = mix(ret, 2*GetBlur3(fract(uv3))*(1-vRadius),kstrength*!inside);
ret -= kstrength*pow(r2,3)*inside*.1;
ret *= 1-4*abs(GetPixel(uv3)-GetPixel(uv3+uTexSize.zw*0.5))*inside*kstrength;

ret = 1-exp(-ret*1.8-.1*vRadius*vRadius);
ret = ret+exp(-12*length((uv10+0.5*2*krad)))*kstrength;


  fragColor = ret;
}
